import{_ as t,o as s,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"46. Supplementary Roster And Additional Shifts","description":"","frontmatter":{"title":"46. Supplementary Roster And Additional Shifts","eba":"Nurses and Midwives 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.md","filePath":"ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.md"}'),o={name:"ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.md"};function n(i,e,l,h,d,p){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_46-supplementary-roster-and-additional-shifts" tabindex="-1">46. Supplementary Roster And Additional Shifts <a class="header-anchor" href="#_46-supplementary-roster-and-additional-shifts" aria-label="Permalink to &quot;46. Supplementary Roster And Additional Shifts&quot;">​</a></h1><p><strong>46.1</strong> In addition to the roster under <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a> (Rosters), the Employer will maintain a supplementary roster.</p><p><strong>46.2</strong> A supplementary roster facilitates additional shifts worked on a voluntary basis. The supplementary roster will:</p><p><strong>(a)</strong> display vacant shifts which Employees can nominate to work; and</p><p><strong>(b)</strong> contain a &#39;stand-by&#39; facility where Employees wishing to work extra shifts can nominate the days/shifts they wish to work should such vacancies arise in the normal roster.</p><p><strong>46.3</strong> Vacancies that arise in the normal roster issued under <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a> will, as far as possible, be filled through the supplementary roster.</p><p><strong>46.4</strong> If a vacancy in the roster:</p><p><strong>(a)</strong> is filled under the supplementary roster, the additional shift is an &#39;additional shift worked by agreement&#39; and does not attract the &#39;change of roster&#39; allowance under <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a> (Rosters);</p><p><strong>(b)</strong> cannot be filled from the supplementary roster, an Employee may be requested to work an additional shift (subject to the provisions of this Agreement) and the additional shift attracts the &#39;change of roster&#39; allowance in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> in addition to any other entitlement on each such occasion.</p><p><strong>46.5</strong> Nothing in this clause prevents an Employer from operating an electronic supplementary roster that:</p><p><strong>(a)</strong> meets the objectives of clause 46.2; and</p><p><strong>(b)</strong> meets the objectives of clause 46.2 in part and by agreement with the Central Implementation Committee at <a href="/eba/ebas/nurses-midwives/union-matters/80-union-matters.html">clause 80.11</a> save that if the Central Implementation Committee is unable to reach agreement regarding the proposed electronic roster, the matter will be referred to a mediator for resolution.</p><p><strong>46.6</strong> A contract of employment that requires an Employee be available for extra shifts does not override this provision.</p><p><strong>46.7</strong> Overtime remains payable where it would otherwise apply, such as double shifts and recall.</p><p><strong>46.8</strong> This clause does not inhibit Employees swapping shifts amongst themselves (subject to operational requirements) in which case no change of roster allowance is payable.</p><p><strong>46.9</strong> Where an Employee is requested by the Employer to work an additional shift other than by the supplementary roster, each such additional shift worked will attract the &quot;change of roster allowance&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> in addition to any other entitlement on each such occasion.</p>',16)])])}const u=t(o,[["render",n]]);export{c as __pageData,u as default};
